690:     /**
691:      * Ensure the following checks are true to make sure that a DeleteShareGroupOffsets request is valid and can be processed further
692:      * 1. Checks whether the provided group is empty
693:      * 2. Checks the requested topics are presented in the metadataImage
694:      * 3. Checks the requested share partitions are initialized for the group
695:      * Once these checks are passed, an appropriate ShareGroupStatePartitionMetadataRecord is created by adding the topics to
696:      * deleting topics list and removing them from the initialized topics list.
697:      *
698:      * @param groupId - The group ID
699:      * @param requestData - The request data for DeleteShareGroupOffsetsRequest
700:      * @return {@link DeleteShareGroupOffsetsResultHolder} an object containing top level error code, list of topic responses
701:      *                                               and persister deleteState request parameters
702:      */
703:     public CoordinatorResult<DeleteShareGroupOffsetsResultHolder, CoordinatorRecord> initiateDeleteShareGroupOffsets(
704:         String groupId,
705:         DeleteShareGroupOffsetsRequestData requestData
706:     ) {
707:         List<CoordinatorRecord> records = new ArrayList<>();
708:         try {
709:             ShareGroup group = groupMetadataManager.shareGroup(groupId);
710:             group.validateDeleteGroup();
711: 
712:             List<DeleteShareGroupOffsetsResponseData.DeleteShareGroupOffsetsResponseTopic> errorTopicResponseList = new ArrayList<>();
713:             List<DeleteShareGroupStateRequestData.DeleteStateData> deleteShareGroupStateRequestTopicsData =
714:                 groupMetadataManager.sharePartitionsEligibleForOffsetDeletion(
715:                     groupId,
716:                     requestData,
717:                     errorTopicResponseList,
718:                     records
719:                 );
720: 
721:             if (deleteShareGroupStateRequestTopicsData.isEmpty()) {
722:                 return new CoordinatorResult<>(
723:                     records,
724:                     new DeleteShareGroupOffsetsResultHolder(Errors.NONE.code(), null, errorTopicResponseList)
725:                 );
726:             }
727: 
728:             DeleteShareGroupStateRequestData deleteShareGroupStateRequestData = new DeleteShareGroupStateRequestData()
729:                 .setGroupId(requestData.groupId())
730:                 .setTopics(deleteShareGroupStateRequestTopicsData);
731: 
732:             return new CoordinatorResult<>(
733:                 records,
734:                 new DeleteShareGroupOffsetsResultHolder(
735:                     Errors.NONE.code(),
736:                     null,
737:                     errorTopicResponseList,
738:                     DeleteShareGroupStateParameters.from(deleteShareGroupStateRequestData)
739:                 )
740:             );
741: 
742:         } catch (GroupIdNotFoundException exception) {
743:             log.debug("Unable to delete share group offsets. GroupId {} not found.", groupId);
744:             return new CoordinatorResult<>(
745:                 records,
746:                 new DeleteShareGroupOffsetsResultHolder(Errors.GROUP_ID_NOT_FOUND.code(), exception.getMessage())
747:             );
748:         } catch (GroupNotEmptyException exception) {
749:             log.debug("Unable to delete share group offsets. Provided group {} is not empty.", groupId);
750:             return new CoordinatorResult<>(
751:                 records,
752:                 new DeleteShareGroupOffsetsResultHolder(Errors.NON_EMPTY_GROUP.code(), exception.getMessage())
753:             );
754:         }
755:     }
