1012:             config.offsetsRetentionCheckIntervalMs(),
1013:             TimeUnit.MILLISECONDS,
1014:             true,
1015:             config.offsetsRetentionCheckIntervalMs(),
1016:             this::cleanupGroupMetadata
1017:         );
1018:     }
