      assertEquals(Errors.NONE, responseMap.get("valid-share-group").getValue());

      // Nonexistent group should NOT be in response (GroupIdNotFoundException is caught)
      assertFalse(responseMap.containsKey("nonexistent-group"));

      // Non-empty group should be in response with NON_EMPTY_GROUP error
      assertTrue(responseMap.containsKey("nonempty-share-group"));
      assertEquals(Errors.NON_EMPTY_GROUP, responseMap.get("nonempty-share-group").getValue());
  }
